INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (102301, 0.0, "アヤネ", "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 2, 401, "2020/07/31 12:00:00", 24001, 2, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (102301, 2.21, "アヤネ", "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 2, 402, "2020/07/31 12:00:00", 24002, 1, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (102301, 0.0, "アヤネ", "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 2, 403, "2020/07/31 12:00:00", 24003, 2, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192201, 1.99, "アサヒ", "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 1, 701, "2020/07/31 12:00:00", 24004, 2, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192201, 2.21, "アサヒ", "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 2, 702, "2020/07/31 12:00:00", 24005, 1, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192201, 3.33, "アサヒ", "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 1, 703, "2020/07/31 12:00:00", 24006, 2, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192301, 0.0, "部員３", "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 2, 801, "2020/07/31 12:00:00", 24007, 2, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192301, 2.68, "部員３", "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 2, 802, "2020/07/31 12:00:00", 24008, 1, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192301, 0.0, "部員３", "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 2, 803, "2020/07/31 12:00:00", 24009, 2, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192501, 0.0, "", "やった！", 1, 501, "2020/07/31 12:00:00", 24010, 1, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192501, 0.0, "", "勝ったよ！", 1, 502, "2020/07/31 12:00:00", 24011, 1, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192501, 0.0, "", "いい調子！", 1, 503, "2020/07/31 12:00:00", 24012, 1, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113501, 5.33, "ミサト", "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 2, 111, "2020/07/31 12:00:00", 24013, 6, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113501, 6.85, "ミサト", "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 2, 112, "2020/07/31 12:00:00", 24014, 1, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113501, 3.0, "ミサト", "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 2, 113, "2020/07/31 12:00:00", 24015, 1, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192401, 6.11, "ダイチ", "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 2, 611, "2020/07/31 12:00:00", 24016, 1, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192401, 6.75, "ダイチ", "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 2, 612, "2020/07/31 12:00:00", 24017, 1, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192401, 0.0, "ダイチ", "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 2, 613, "2020/07/31 12:00:00", 24018, 2, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113401, 4.52, "ハツネ", "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 1, 211, "2020/07/31 12:00:00", 24019, 2, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113401, 3.89, "ハツネ", "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 1, 212, "2020/07/31 12:00:00", 24020, 2, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113401, 13.49, "ハツネ", "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 2, 213, "2020/07/31 12:00:00", 24021, 1, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (106501, 3.17, "カヤ", "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 2, 311, "2020/07/31 12:00:00", 24022, 1, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (106501, 4.42, "カヤ", "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 2, 312, "2020/07/31 12:00:00", 24023, 1, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (106501, 2.89, "カヤ", "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 1, 313, "2020/07/31 12:00:00", 24024, 6, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (102301, 3.71, "アヤネ", "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 3, 421, "2020/07/31 12:00:00", 24025, 4, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192201, 5.1, "アサヒ", "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 1, 721, "2020/07/31 12:00:00", 24026, 2, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192301, 4.34, "部員３", "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 3, 821, "2020/07/31 12:00:00", 24027, 1, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (192501, 0.0, "", "いい勝負だったよ\nまたやろうね", 1, 521, "2020/07/31 12:00:00", 24028, 1, 0.0, 0.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113501, 5.62, "ミサト", "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 2, 101, "2020/07/31 12:00:00", 24029, 1, 0.0, -360.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113501, 9.58, "ミサト", "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 2, 102, "2020/07/31 12:00:00", 24030, 1, 0.0, -360.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113501, 0.0, "ミサト", "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 2, 103, "2020/07/31 12:00:00", 24031, 2, 0.0, -360.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113501, 9.13, "ミサト", "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 1, 104, "2020/07/31 12:00:00", 24032, 2, 0.0, -360.0, "2030/12/17 14:59:59", 10046, 24);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (113501, 8.27, "ミサト", "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 2, 105, "2020/07/31 12:00:00", 24033, 1, 0.0, -360.0, "2030/12/17 14:59:59", 10046, 24);
